    std::cout << "Enter a mileage: ";
    std::cin >> mileage;

    // 3. On applique la fameuse formule mathématique
    double estimatedPrice = theta0 + (theta1 * mileage);

    // 4. On affiche le résultat
    std::cout << "The estimated price is: " << estimatedPrice << std::endl;

    return 0;
}
```

